
const columns = [
  {
    title: "任务编号",
    dataIndex: "taskCode",
    key: "taskCode",
  },
  {
    title: "报告编号",
    dataIndex: "reportCode",
    key: "reportCode",
  },

  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "本单费用",
    dataIndex: "countPrice",
    key: "countPrice",
  },
  {
    title: "要求完成日期",
    key: "requestDate",
    dataIndex: "requestDate",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

const columns1 = [
  {
    title: "任务编号",
    dataIndex: "taskCode",
    key: "taskCode",
  },
  {
    title: "报告编号",
    dataIndex: "reportCode",
    key: "reportCode",
  },
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "本单费用",
    dataIndex: "countPrice",
    key: "countPrice",
  },
  {
    title: "要求完成日期",
    key: "requestDate",
    dataIndex: "requestDate",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];
const sampleColumns: any = [
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "技术指标",
    dataIndex: "specsContent",
    key: "specsContent",
  },
  {
    title: "检测结果",
    dataIndex: "checkResult",
    key: "checkResult",
  },
  {
    title: "判定结果",
    dataIndex: "judgeResult",
    key: "judgeResult",
  },
];
import {
  defineComponent,
  onMounted,
  provide,
  reactive,
  ref,
  toRefs,
  watch,
} from "vue";
import {
  reportList,
  historicalReport,
  commitApprove,
  reportDownloadList,
  reportDownloadListHistory,
  reportDetail,
  getTeamUserName,
} from "@/server/http/api/Amultitasking";
import SelectCheck from "./model/Reportgeneration/SelectCheck.vue";
import CheckDetail from "./model/Reportgeneration/CheckDetail.vue";
import SelectCheckTwo from "./model/Reportgeneration/SelectCheckTwo.vue";
export default defineComponent({
  name: "Reportgeneration",
  components: { CheckDetail, SelectCheck, SelectCheckTwo },
  setup() {
    let active = ref(0);
    const total = ref(0);
    const optionsModal = reactive({
      visible: false,
      confirmLoading: false,
      title: "",
      tableDetailList: [],
    });
    const team: any = reactive({
      approverVo: [],
      signerVo: [],
    });
    onMounted(() => {
      getTeamUserName().then((res: any) => {
        if (res.data.code === 200) {
          team.approverVo = res.data.data.approverVo.map((item: any) => ({
            label: item.label,
            value: `${item.label}&${item.value}`,
          }));
          team.signerVo = res.data.data.signerVo.map((item: any) => ({
            label: item.label,
            value: `${item.label}&${item.value}`,
          }));
        }
      });
    });
    let datatList = ref([]);
    let options = reactive({
      searchValue: "",
      pageNum: 1,
      pageSize: 10,
    });
    const searchReportList = () => {
      reportDownloadList({
        search: options.searchValue,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告生成", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    };
    const searchHistoricalReport = () => {
      reportDownloadListHistory({
        search: options.searchValue,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("历史查询", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    };
    watch(active, (newval) => {
      datatList.value = [];
      if (newval == 0) {
        searchReportList();
      } else {
        searchHistoricalReport();
      }
    });

    let timer: any;
    watch(
      options,
      () => {
        if (active.value == 0) {
          clearTimeout(timer);
          timer = setTimeout(() => {
            searchReportList();
          }, 400);
        } else {
          clearTimeout(timer);
          timer = setTimeout(() => {
            searchHistoricalReport();
          }, 400);
        }
      },
      {
        immediate: true,
      }
    );
    function commit(id: number) {
      commitApprove(id).then((res: any) => {
        // //console.log("报告审批", res);
        if (res.data.code === 200) {
          searchReportList();
        }
      });
    }
    function detail(id: number) {
      optionsModal.visible = true;
      optionsModal.title = "";
      optionsModal.tableDetailList = [];
      reportDetail(id).then((res: any) => {
        // //console.log("报告合成详情", res);
        if (res.data.code === 200) {
          optionsModal.title = res.data.data.sampleName;
          optionsModal.tableDetailList = res.data.data.checkItemInfo;
        }
      });
    }

    function handleOk() {
      optionsModal.visible = false;
    }
    provide("searchReportList", searchReportList);
    function onSearch() {}
    return {
      onSearch,
      datatList,
      columns,
      columns1,
      commit,
      active,
      total,
      ...toRefs(options),
      detail,
      handleOk,
      ...toRefs(optionsModal),
      sampleColumns,
      team,
      searchReportList,
    };
  },
});
