
const columns = [
  {
    title: "报告名称",
    dataIndex: "reportName",
    key: "reportName",
  },
  {
    title: "编号",
    dataIndex: "reportCode",
    key: "reportCode",
  },

  {
    title: "操作",

    key: "action",
    slots: { customRender: "action" },
  },
];

import { defineComponent, inject, reactive, ref } from "vue";
import {
  getTemplateList,
  approval_download,
  commitApprove,
} from "@/server/http/api/Amultitasking";
import PreviewCheck from "./PreviewCheck.vue";
export default defineComponent({
  props: ["productId", "id", "team"],
  components: { PreviewCheck },
  setup(props) {
    const searchReportList: any = inject("searchReportList");
    const formRef = ref();
    const confirmLoading = ref(false);
    const formState = reactive({
      verifyer: [],
      issuer: [],
      reportUrl: "",
    });
    const rules = {
      verifyer: [
        {
          required: true,
          message: "请选择审核人",
          trigger: "blur",
        },
      ],
      issuer: [
        {
          required: true,
          message: "请选择签发人",
          trigger: "blur",
        },
      ],
      // reportUrl: [
      //   {
      //     required: true,
      //     message: "请选择报告模板",
      //     trigger: "blur",
      //   },
      // ],
    };

    const visible = ref<boolean>(false);
    const dataSource = ref([]);
    const showModal = () => {
      formState.verifyer = [];
      formState.issuer = [];
      formState.reportUrl = "";

      getTemplateList(props.id).then((res: any) => {
        if (res.data.code === 200) {
          dataSource.value = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      confirmLoading.value = true;
      formRef.value
        .validate()
        .then(() => {
          commitApprove({
            entrustmentId: props.id,
            verifyer: formState.verifyer,
            issuer: formState.issuer,
          }).then((res: any) => {
            if (res.data.code === 200) {
              searchReportList();
            }
            visible.value = false;
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          confirmLoading.value = false;

          //console.log("error", error);
        });
      //console.log(e);
    };
    function downLoad(record: any) {
      approval_download(props.id, record.reportFileUri).then((res: any) => {
        //console.log(res);
        const link = document.createElement("a");
        link.style.display = "none";
        link.setAttribute("href", res.data);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      });
    }
    function preview() {}
    function selectCheck(reportFileUri: any) {
      formState.reportUrl = reportFileUri;
    }
    return {
      visible,
      showModal,
      handleOk,
      columns,
      dataSource,
      downLoad,
      preview,
      formState,
      selectCheck,
      formRef,
      labelCol: { span: 4 },
      wrapperCol: { span: 14 },
      rules,
      confirmLoading,
    };
  },
});
