
import { defineComponent, ref } from "vue";
import config from "@/server/http/config";
export default defineComponent({
  props: ["reportCode"],
  setup() {
    const visible = ref<boolean>(false);

    const showModal = () => {
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
      config,
    };
  },
});
